def get_hippodrome_info(nom_normalise: str):
    nom = nom_normalise.lower().strip()
    if nom in HIPPODROME_ALIASES: nom = HIPPODROME_ALIASES[nom]
    if nom in HIPPODROMES_DB: return HIPPODROMES_DB[nom]
    for cle, info in HIPPODROMES_DB.items():
        if cle in nom or nom in cle: return info
    return None
